const text = $input.first().json.message.text;
const chatId = $input.first().json.message.chat.id;
const userId = $input.first().json.message.from.id;
const match = text.match(/\/learn\s+(https?:\/\/\S+)/);
if (!match) {
  return [{ json: { error: true, chatId, message: "Please provide a URL after /learn command.\nExample: /learn https://example.com/article" } }];
}
return [{ json: { url: match[1], chatId, userId } }];

const material = $input.first().json;
const summary = typeof material === "string" ? JSON.parse(material) : material;
// const keyPoints = summary.keyPoints.map((p, i) => `${i + 1}. ${p}`).join("");
// const concepts = summary.mainConcepts.join(", ");
const message = `✅ Material saved!

` +
  `📚 ${$('Prepare for Teacher').first().json.title}

` +
  `🎯 Key Points:
${summary.keyPoints}

` +
  `💡 Main Concepts:
${summary.mainConcepts}

` +
  `📊 Difficulty: ${summary.diff}

` +
  `Use /quiz to test your knowledge!`;
return [{ json: { chatId: $("Prepare for Teacher").item.json.chatId, message } }];

const data = $input.first().json.callback_query.data;
const chatId = $input.first().json.callback_query.message.chat.id;
const messageId = $input.first().json.callback_query.message.message_id;
const topicId = parseInt(data.replace("topic_", ""));
const token = $input.first().json.token
return [{ json: { topicId, chatId, messageId, token } }];

const quiz = $('Examiner Agent').first().json.output;
const questions = typeof quiz.questions === "string" ? JSON.parse(quiz.questions) : quiz.questions;
const firstQ = questions[0];
const chatId = $('Extract Topic ID').first().json.chatId;
const quizId = $('Extract Topic ID').first().json.topicId;

const buttons = firstQ.options.map((opt, index) => ({
  text: opt,
  callback_data: `answer_${quizId}_${firstQ.id}_${index}`
}));

const message = `Question 1 of ${questions.length}:\n\n${firstQ.question}`;

return [{ json: { chatId, message, buttons, quizId, currentQuestion: 1, totalQuestions: questions.length } }];

const data = $input.first().json.callback_query.data;
const chatId = $input.first().json.callback_query.message.chat.id;
const parts = data.replace("answer_", "").split("_");
const quizId = 'topic_' + parseInt(parts[0]);
const questionId = parts[1];
const answer = parts[2];
return [{ json: { quizId, questionId, answer, chatId } }];

const parsed = $('Parse Answer').first().json;
const correct = $('Get Quiz').first().json;

const chosenIdx = parseInt(parsed.answer);
const correctLetter = parseInt(correct.correctAnswerIdx);
const isCorrect = chosenIdx === correctLetter;

return [{ json: {
  isCorrect,
  chosenIdx,
  correctLetter,
  chatId: parsed.chatId,
  quizId: parsed.quizId,
  questionId: parsed.questionId
}}];

const answers = $input.all().map(item => item.json);
const correct = answers.filter(a => a.isCorrect).length;
const total = answers.length;
const percentage = Math.round((correct / total) * 100);
const chatId = $("Validate Answer").item.json.chatId;
let emoji = "🎉";
if (percentage < 60) emoji = "📚";
else if (percentage < 80) emoji = "👍";
let feedback = "";
if (percentage >= 80) feedback = "Excellent work! 🌟";
else if (percentage >= 60) feedback = "Good job! Keep learning! 💪";
else feedback = "Keep studying! You will improve! 📖";
const message = `${emoji} Quiz Complete!\n\nScore: ${correct}/${total} (${percentage}%)\n\n${feedback}`;
return [{ json: { chatId, message } }];

const data = $input.first().json.output


// Parse the string into a real array
const keypoints = typeof data.keyPoints === 'string' 
  ? JSON.parse(data.keyPoints) 
  : data.keyPoints;

const mainconc = typeof data.mainConcepts === 'string' 
  ? JSON.parse(data.mainConcepts) 
  : data.mainConcepts;

return [{
  json: {
    mainconc: '• ' + mainconc.join('\n• '),
    keypoints: '• ' + keypoints.join('\n• ')  // now a clean string
  }
}];

const materials = $input.all().map(item => item.json);
const chatId = $('Telegram Bot').first().json.message.from.id
const buttons = materials.map(m => ({
  text: `${m.topic} (${m.diff})`,
  callback_data: `topic_${m.id}`
}));
return [{ json: { chatId, buttons } }];

const data = $input.first().json;

const inline_keyboard = data.buttons.map(btn => ([{
  text: btn.text,
  callback_data: btn.callback_data
}]));

return [{
  json: {
    chatId: data.chatId,
    message: "Select a topic for your quiz:",
    reply_markup: JSON.stringify({ inline_keyboard })
  }
}];

const data = $input.first().json;
return [{
  json: {
    ...data,
    message: data.message.replace(/\n/g, '\\n'),
    reply_markup: JSON.stringify({
      inline_keyboard: data.buttons.map(b => ([{
        text: b.text,
        callback_data: b.callback_data
      }]))
    })
  }
}];

const output = $input.first().json.output;
const questions = output.questions;
const materialId = $('Route by Command').first().json.callback_query.data;

return questions.map(q => ({
  json: {
    materialId,
    questionId: q.id,
    question: q.question,
    correctAnswerIdx: q.correctAnswer.charCodeAt(0) - 'A'.charCodeAt(0),
    options: q.options.join(', '),
    explanation: q.explanation ?? ''
  }
}));

for (const item of $input.all()) {
  if (item.json.answeredAt === null )
    return {hasMore: true}
}

return {hasMore: false}

const data = $input.first().json;
const letters = ['A', 'B', 'C', 'D'];

return [{
  json: {
    ...data,
    chosenLetter: letters[data.chosenIdx],
    correctLetter: letters[data.correctLetter]
  }
}];

const rows = $('Get quiz questions').all()
const unanswered = rows.filter(r => r.json.answeredAt === null);

const firstQ = unanswered[0].json;
const chatId = $('Get quiz questions').first().json.userId

const options = firstQ.options.split(/, (?=[A-D][.)]\s)/);
const buttons = options.map((opt, index) => ({
  text: opt,
  callback_data: `answer_${firstQ.materialId.replace('topic_', '')}_${firstQ.questionId}_${index}`
}));

const answeredCount = rows.length - unanswered.length;
const message = `Question ${answeredCount + 1} of ${rows.length}:\n\n${firstQ.question}`;

return [{ json: { chatId, message, buttons, materialId: firstQ.materialId, currentQuestionId: firstQ.questionId } }];

const data = $input.first().json;
return [{
  json: {
    ...data,
    message: data.message.replace(/\n/g, '\\n'),
    reply_markup: JSON.stringify({
      inline_keyboard: data.buttons.map(b => ([{
        text: b.text,
        callback_data: b.callback_data
      }]))
    })
  }
}];

